package main
// Fiber Performance Dashboard (EN)
import ("fmt";"math/rand";"os";"runtime";"time";"github.com/gofiber/fiber/v2";"github.com/gofiber/fiber/v2/middleware/logger")
var startTime = time.Now()
func main() {
	app := fiber.New(fiber.Config{AppName:"Fiber Dashboard",DisableStartupMessage:true}); app.Use(logger.New())
	app.Get("/", func(c *fiber.Ctx) error { c.Set("Content-Type","text/html; charset=utf-8"); return c.SendString(dash()) })
	app.Get("/api/users", func(c *fiber.Ctx) error { return c.JSON([]fiber.Map{{"id":1,"name":"Alice"},{"id":2,"name":"Bob"},{"id":3,"name":"Carol"}}) })
	app.Get("/api/health", func(c *fiber.Ctx) error { var m runtime.MemStats; runtime.ReadMemStats(&m); return c.JSON(fiber.Map{"status":"healthy","memory_mb":m.Alloc/1024/1024,"goroutines":runtime.NumGoroutine()}) })
	port := os.Getenv("PORT"); if port == "" { port = "3000" }; app.Listen(":"+port)
}
func dash() string {
	up := time.Since(startTime).Round(time.Second); var m runtime.MemStats; runtime.ReadMemStats(&m); mb := m.Alloc/1024/1024; gr := runtime.NumGoroutine()
	bars := ""; days := []string{"Mon","Tue","Wed","Thu","Fri","Sat","Sun"}
	for i,d := range days { h:=25+rand.Intn(65); bars+=fmt.Sprintf(`<div class="bg"><div class="b" style="height:%d%%;animation-delay:%.2fs"></div><div class="bl">%s</div></div>`,h,0.3+float64(i)*0.08,d) }
	mets := []struct{l,v,i,c string}{{"Response","<1ms","⚡","#f59e0b"},{"Memory",fmt.Sprintf("%dMB",mb),"💾","#8b5cf6"},{"Goroutines",fmt.Sprintf("%d",gr),"🔄","#06b6d4"},{"QPS",fmt.Sprintf("%d",1000+rand.Intn(4000)),"📊","#ec4899"}}
	mh := ""; for _,mt := range mets { mh += fmt.Sprintf(`<div class="pf"><div class="pi" style="background:%s18">%s</div><div class="px"><div class="pl">%s</div><div class="pv" style="color:%s">%s</div></div></div>`,mt.c,mt.i,mt.l,mt.c,mt.v) }
	return fmt.Sprintf(`<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0,user-scalable=no"><title>Fiber</title><style>*{margin:0;padding:0;box-sizing:border-box}:root{--bg:#080816;--card:rgba(255,255,255,0.035);--border:rgba(255,255,255,0.07);--text:#f0f0ff;--text2:rgba(240,240,255,0.55);--text3:rgba(240,240,255,0.3);--teal:#14b8a6;--radius:14px}body{font-family:-apple-system,BlinkMacSystemFont,sans-serif;background:var(--bg);color:var(--text);min-height:100vh}.c{max-width:460px;margin:0 auto;padding:0 14px 32px;position:relative;z-index:1}.hdr{padding:20px 2px;display:flex;justify-content:space-between;align-items:center}.hdr h1{font-size:22px;font-weight:800;background:linear-gradient(135deg,#14b8a6,#2dd4bf);-webkit-background-clip:text;-webkit-text-fill-color:transparent}.hdr p{font-size:12px;color:var(--text2)}.badge{font-size:11px;font-weight:600;padding:5px 12px;border-radius:20px;background:rgba(20,184,166,0.1);color:var(--teal)}.row{display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:16px}.m{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);padding:14px;text-align:center}.m-val{font-size:20px;font-weight:800}.m-label{font-size:10px;color:var(--text2);text-transform:uppercase}.m:nth-child(1) .m-val{color:#00d4aa}.m:nth-child(2) .m-val{color:var(--teal)}.m:nth-child(3) .m-val{color:#8b5cf6}.card{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);padding:18px;margin-bottom:14px}.card-h{display:flex;justify-content:space-between;align-items:center;margin-bottom:14px}.card-t{font-size:15px;font-weight:700}.card-b{font-size:10px;font-weight:600;padding:3px 9px;border-radius:16px;background:rgba(20,184,166,0.1);color:var(--teal)}.pf{display:flex;align-items:center;gap:12px;padding:10px 0;border-bottom:1px solid rgba(255,255,255,0.03)}.pf:last-child{border:none}.pi{width:36px;height:36px;border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0}.px{flex:1}.pl{font-size:12px;color:var(--text2)}.pv{font-size:16px;font-weight:700}.chart{display:flex;align-items:flex-end;justify-content:space-between;height:120px;gap:6px}.bg{flex:1;display:flex;flex-direction:column;align-items:center;gap:4px;height:100%%;justify-content:flex-end}.b{width:100%%;max-width:28px;border-radius:5px 5px 3px 3px;background:linear-gradient(180deg,#2dd4bf,#0d9488);transform-origin:bottom;animation:grow .7s cubic-bezier(.34,1.56,.64,1) backwards}@keyframes grow{from{transform:scaleY(0)}to{transform:scaleY(1)}}.bl{font-size:9px;color:var(--text3)}.try{background:rgba(20,184,166,0.1);color:var(--teal);border:1px solid rgba(20,184,166,0.2);padding:6px 14px;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer}.result{margin-top:10px;padding:12px;background:rgba(0,0,0,0.3);border-radius:8px;font-family:monospace;font-size:11px;color:#00d4aa;max-height:180px;overflow-y:auto;display:none;white-space:pre-wrap}.ft{text-align:center;padding:12px}.ft-b{font-size:10px;font-weight:600;color:var(--text3);padding:5px 12px;border-radius:20px;background:rgba(20,184,166,0.04)}@keyframes fadeIn{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}.m,.card{animation:fadeIn .5s ease backwards}</style></head><body>
<div class="c"><div class="hdr"><div><h1>🔥 Fiber Dashboard</h1><p>Ultra-Fast Go Web Framework</p></div><div class="badge">Running</div></div>
<div class="row"><div class="m"><div class="m-val">%s</div><div class="m-label">Uptime</div></div><div class="m"><div class="m-val">%dMB</div><div class="m-label">Memory</div></div><div class="m"><div class="m-val">%d</div><div class="m-label">Goroutines</div></div></div>
<div class="card"><div class="card-h"><span class="card-t">Performance</span><span class="card-b">⚡ Live</span></div>%s</div>
<div class="card"><div class="card-h"><span class="card-t">Throughput</span><span class="card-b">📊 Weekly</span></div><div class="chart">%s</div></div>
<div class="card"><div class="card-h"><span class="card-t">Live Test</span><span class="card-b">🧪</span></div><div style="display:flex;gap:8px"><button class="try" onclick="tryApi('/api/users')">👥 Users</button><button class="try" onclick="tryApi('/api/health')">💚 Health</button></div><div class="result" id="r"></div></div>
<div class="ft"><div class="ft-b">Fiber v2 · Go %s · Running</div></div></div>
<script>function tryApi(u){var r=document.getElementById('r');r.style.display='block';r.textContent='⏳';fetch(u).then(function(x){return x.json()}).then(function(d){r.textContent=JSON.stringify(d,null,2)}).catch(function(e){r.textContent='❌ '+e.message})}</script></body></html>`,up,mb,gr,mh,bars,runtime.Version())
}
